+// ── 6. Merge associativity ────────────────────────────────────────────────
+
+proptest! {
+    #![proptest_config(ProptestConfig::with_cases(80))]
+
+    #[test]
+    fn merge_is_associative(
+        a in arb_counter(30),
+        b in arb_counter(30),
+        c in arb_counter(30),
+    ) {
+        // (a merge b) merge c
+        let mut ab = a.clone();
+        ab.merge(&b);
+        let mut ab_c = ab;
+        ab_c.merge(&c);
+
+        // a merge (b merge c)
+        let mut bc = b.clone();
+        bc.merge(&c);
+        let mut a_bc = a.clone();
+        a_bc.merge(&bc);
+
+        prop_assert!(
+            (ab_c.total() - a_bc.total()).abs() < 1e-9,
+            "merge not associative: {}, {}",
+            ab_c.total(), a_bc.total()
+        );
+
+        let all_ids: std::collections::HashSet<_> = ab_c.state_ids()
+            .union(&a_bc.state_ids())
+            .cloned()
+            .collect();
+        for from in &all_ids {
+            for to in &all_ids {
+                let c1 = ab_c.count(from, to);
+                let c2 = a_bc.count(from, to);
+                prop_assert!(
+                    (c1 - c2).abs() < 1e-9,
+                    "merge not associative for {from}->{to}: {c1} vs {c2}"
+                );
+            }
+        }
+    }
+}
