+        for (from, to) in &transitions {
+            predictor.record_transition(from.clone(), to.clone());
+        }
+
+        for screen in predictor.counter().state_ids() {
+            for pred in predictor.predict(&screen) {
+                prop_assert!(
+                    pred.probability > 0.0,
